mapper.select:
SELECT ia.*, CASE WHEN ia.apply_type = 2 THEN r.name WHEN ia.apply_type = 1 THEN IFNULL(u.nickname, u.username) ELSE '' END AS riderName FROM invoice_apply ia LEFT JOIN rider r ON ia.apply_type = 2 AND ia.target_id = r.rider_id LEFT JOIN `user` u ON ia.apply_type = 1 AND ia.target_id = u.id
and ia.status = #{status}
ORDER BY ia.create_time DESC

mapper.update:
update invoice_apply
set status = #{status},update_time = now()
where id = #{id}
